// src/Gallery.jsx
import { useState, useRef, useEffect } from 'react'
import { DndProvider, useDrag, useDrop } from 'react-dnd'
import { HTML5Backend } from 'react-dnd-html5-backend'
import { BiMove } from 'react-icons/bi'
import {styled} from 'styled-components'          // ← This line was missing

// ─── Drag & Drop Types ───────────────────────────────────────────────────────
const ItemTypes = { IMAGE: 'image' }

// ─── Styled Components ───────────────────────────────────────────────────────
const GalleryContainer = styled.div`
  padding: 2rem;
  max-width: 1200px;
  margin: 0 auto;
  background: #f8f9fa;
  min-height: 100vh;
`

const GalleryGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 1.5rem;
  padding: 1rem;
`

const GalleryImage = styled.div`
  position: relative;
  border-radius: 12px;
  overflow: hidden;
  box-shadow: 0 4px 15px rgba(0,0,0,0.1);
  transition: all 0.3s ease;
  cursor: grab;
  height: 300px;
  background: #eee;

  &:hover {
    transform: scale(1.02);
    box-shadow: 0 8px 25px rgba(0,0,0,0.15);
  }

  &.selected {
    border: 3px solid #007bff;
    box-shadow: 0 0 0 3px rgba(0,123,255,0.25);
  }

  &:active {
    cursor: grabbing;
  }

  img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }
`

const DragHandle = styled.div`
  position: absolute;
  top: 10px;
  right: 10px;
  background: rgba(0,0,0,0.6);
  color: white;
  border-radius: 50%;
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transition: opacity 0.2s;

  ${GalleryImage}:hover &,
  ${GalleryImage}.selected & {
    opacity: 1;
  }

  svg {
    font-size: 16px;
  }
`

// ─── Draggable Image Component ───────────────────────────────────────────────
function DraggableImage({ id, imageUrl, index, moveImage, isSelected, onSelect }) {
  const ref = useRef(null)

  const [{ isDragging }, drag] = useDrag({
    type: ItemTypes.IMAGE,
    item: { id, index },
    collect: (monitor) => ({ isDragging: monitor.isDragging() }),
  })

  const [, drop] = useDrop({
    accept: ItemTypes.IMAGE,
    hover: (item) => {
      if (item.index !== index) {
        moveImage(item.index, index)
        item.index = index
      }
    },
  })

  drag(drop(ref))

  return (
    <GalleryImage
      ref={ref}
      style={{ opacity: isDragging ? 0.5 : 1 }}
      className={isSelected ? 'selected' : ''}
      onClick={() => onSelect(id)}
      data-id={id}
    >
      <img src={imageUrl} alt={`Gallery ${id}`} />
      <DragHandle title="Drag to reorder">
        <BiMove />
      </DragHandle>
    </GalleryImage>
  )
}

// ─── Main Gallery ────────────────────────────────────────────────────────────
function Gallery() {
  const [images, setImages] = useState([
    { id: 1, url: 'data:image/jpeg;base64,' },
    { id: 2, url: 'data:image/jpeg;base64,' },
    { id: 3, url: 'data:image/jpeg;base64,' },
    { id: 4, url: 'data:image/jpeg;base64,' },
    { id: 5, url: 'data:image/jpeg;base64,' },
    { id: 6, url: 'data:image/jpeg;base64,' },
    { id: 7, url: 'data:image/jpeg;base64,' },
    { id: 8, url: 'data:image/jpeg;base64,' },
  ])

  const [selectedId, setSelectedId] = useState(null)
  const galleryRef = useRef(null)

  const moveImage = (fromIndex, toIndex) => {
    const newImages = [...images]
    const [moved] = newImages.splice(fromIndex, 1)
    newImages.splice(toIndex, 0, moved)
    setImages(newImages)
  }

  const onSelect = (id) => {
    setSelectedId(id)
    const el = galleryRef.current?.querySelector(`[data-id="${id}"]`)
    el?.scrollIntoView({ behavior: 'smooth', block: 'nearest' })
  }

  // Keyboard navigation (optional)
  useEffect(() => {
    const handleKey = (e) => {
      if (!selectedId) return
      const idx = images.findIndex(i => i.id === selectedId)
      let next = idx

      if (e.key === 'ArrowLeft')  next = Math.max(0, idx - 1)
      if (e.key === 'ArrowRight') next = Math.min(images.length - 1, idx + 1)
      if (e.key === 'ArrowUp')    next = Math.max(0, idx - 3)
      if (e.key === 'ArrowDown')  next = Math.min(images.length - 1, idx + 3)
      if (e.key === 'Escape')     { setSelectedId(null); return }

      if (next !== idx) {
        e.preventDefault()
        setSelectedId(images[next].id)
        const el = galleryRef.current?.querySelector(`[data-id="${images[next].id}"]`)
        el?.focus()
      }
    }

    window.addEventListener('keydown', handleKey)
    return () => window.removeEventListener('keydown', handleKey)
  }, [selectedId, images])

  return (
    <DndProvider backend={HTML5Backend}>
      <GalleryContainer>
        <h1 className="text-center mb-4">Interactive Image Gallery</h1>
        <p className="text-center mb-5 text-muted">
          Drag images to reorder • Click to select • Use arrow keys to move • ESC to deselect
        </p>

        <GalleryGrid ref={galleryRef}>
          {images.map((img, idx) => (
            <DraggableImage
              key={img.id}
              id={img.id}
              imageUrl={img.url}
              index={idx}
              moveImage={moveImage}
              isSelected={selectedId === img.id}
              onSelect={onSelect}
            />
          ))}
        </GalleryGrid>

        <div className="text-center mt-4">
          <small className="text-muted">
            Selected: {selectedId ? `Image #${selectedId}` : 'None'}
          </small>
        </div>
      </GalleryContainer>
    </DndProvider>
  )
}

export default Gallery